SELECT portfolio_id, SUM(investment_value) AS total_investment
FROM client_investments
GROUP BY portfolio_id;

SELECT SUM(shares_changed) AS total_shares_changed
FROM investment_activities
WHERE fund_id = 1;

SELECT total_shares
FROM hedge_funds
WHERE fund_id = 1;

SELECT fund_name, total_value
FROM hedge_funds
ORDER BY total_value DESC;

SELECT SUM(investment_value) AS total_investment_value
  FROM client_investments
  WHERE fund_id = 0;

SELECT manager_name
FROM fund_managers
ORDER BY manager_name;
